// Función para limpiar enlaces de imágenes y videos
function cleanImageLinks(text) {
    // Limpiar texto y normalizar espacios
    let cleanText = text
        .replace(/PROTECTED\*/g, '') // Eliminar restos de PROTECTED
        .replace(/__\[.*?\]__/g, '') // Eliminar placeholders
        .replace(/\s+/g, ' ') // Normalizar espacios
        .trim();

   //limpiar astericos
    cleanText = cleanText
        .replace(/\*+/g, '') 
         .replace(/!+/g, '') 
        .replace(/\s+/g, ' ') // Normalizar espacios después de eliminar asteriscos
        .trim();

    // Patrones para detectar enlaces de imágenes/videos
    const imagePatterns = [
        // Enlaces con extensiones de imagen/video
        /https?:\/\/[^\s\)]*\.(jpg|jpeg|png|gif|webp|mp4|mov|avi|webm)/gi,
        // Enlaces específicos de Hyundai con imágenes
        /https?:\/\/[^\s\)]*hyundai[^\s\)]*images[^\s\)]*/gi,
        // Enlaces entre paréntesis que terminan en extensiones
        /\([^)]*https?:\/\/[^)]*\.(jpg|jpeg|png|gif|webp|mp4|mov|avi|webm)[^)]*\)/gi,
        // Enlaces entre corchetes
        /\[[^\]]*https?:\/\/[^\]]*\.(jpg|jpeg|png|gif|webp|mp4|mov|avi|webm)[^\]]*\]/gi,
        // Markdown de imágenes completo
        /!\[[^\]]*\]\([^)]*https?:\/\/[^)]*\)/gi
    ];

    // Aplicar todos los patrones
    imagePatterns.forEach(pattern => {
        cleanText = cleanText.replace(pattern, '');
    });

    // Filtros adicionales para resabios
    cleanText = cleanText
        // Eliminar corchetes con nombres de modelos
        .replace(/\[New Tucson\]/gi, '')
        .replace(/\[New Creta\]/gi, '')
        .replace(/\[HB20\]/gi, '')
        .replace(/\[Staria\]/gi, '')
        .replace(/\[Veloster\]/gi, '')
        // Eliminar cualquier corchete con "New" + modelo
        .replace(/\[New [^\]]+\]/gi, '')
        // Eliminar corchetes con solo nombres de modelos (patrón general)
        .replace(/\[(Tucson|Creta|HB20|Staria|Veloster|TUCSON|CRETA|VELOSTER)\]/gi, '')
        // Eliminar corchetes vacíos o con espacios
        .replace(/\[\s*\]/g, '')
        // Eliminar doble espacios que puedan quedar
        .replace(/\s+/g, ' ');

    // Limpiar líneas que solo contengan enlaces
    const lines = cleanText.split('\n');
    const filteredLines = lines.filter(line => {
        const trimmedLine = line.trim();
        // Eliminar líneas que son solo enlaces
        if (trimmedLine.match(/^https?:\/\//)) return false;
        // Eliminar líneas que solo tienen texto de enlace sin contenido útil
        if (trimmedLine.match(/^\[.*\]\(.*\)$/)) return false;
        return trimmedLine.length > 0;
    });

    // Reconstruir el texto
    cleanText = filteredLines.join('\n').trim();

    // Limpiar espacios extra y líneas vacías consecutivas
    cleanText = cleanText
        .replace(/\n\s*\n\s*\n/g, '\n\n') // Max 2 saltos de línea consecutivos
        .replace(/^\s+|\s+$/g, '') // Espacios al inicio y final
        .replace(/\s+/g, ' '); // Espacios múltiples a uno solo

    return cleanText;
}

// Aplicar la limpieza
const cleanedOutput = cleanImageLinks(outputText);

